from abc import ABC, abstractmethod

class PricingStrategy(ABC):
    # Strategy interface — all strategies must implement calculate()
    @abstractmethod
    def calculate(self, base_price: float) -> float:
        pass

class RegularPricing(PricingStrategy):
    # Standard pricing — no discount applied
    def calculate(self, base_price: float) -> float:
        return base_price  # Full price, no modifications

class HolidayPricing(PricingStrategy):
    # 20% discount during holiday season
    def calculate(self, base_price: float) -> float:
        return base_price * 0.80  # Apply 20% seasonal discount

class ClearancePricing(PricingStrategy):
    # 50% discount for clearance items
    def calculate(self, base_price: float) -> float:
        return base_price * 0.50  # Half off to clear inventory

class PriceCalculator:
    # Context class that uses a strategy — can swap strategies anytime
    def __init__(self, strategy: PricingStrategy):
        # Accept any strategy that follows the PricingStrategy interface
        self._strategy = strategy  # Store the initial pricing strategy

    def set_strategy(self, strategy: PricingStrategy):
        # Change strategy at runtime — like switching from regular to holiday
        self._strategy = strategy  # Swap to a different pricing model

    def calculate_price(self, base_price: float) -> float:
        return self._strategy.calculate(base_price)

# Usage — strategies are interchangeable objects
calc = PriceCalculator(RegularPricing())
print(f"Regular: ${calc.calculate_price(100):.2f}")
calc.set_strategy(HolidayPricing())
print(f"Holiday: ${calc.calculate_price(100):.2f}")
# Expected output:
# Regular: $100.00
# Holiday: $80.00
